diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 394dfca262e1..66845b020e32 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3552,6 +3552,93 @@ static bool hasAffectedValue(Value *V, SmallPtrSetImpl<Value *> &Affected,
   return false;
 }

+
+/// Fold select of symmetric selects with the same condition.
+/// Pattern: select c2, (select c1, a, b), (select c1, b, a)
+///   --> select (xor c1, c2), b, a
+///
+/// This is based on the identity:
+///   c2 ? (c1 ? a : b) : (c1 ? b : a)
+/// = (c2 && c1) ? a : (c2 && !c1) ? b : (!c2 && c1) ? b : a
+/// = (c1 == c2) ? a : b
+/// = (c1 xor c2) ? b : a
+static Instruction *foldSelectOfSymmetricSelects(SelectInst &SI,
+                                                 InstCombiner::BuilderTy &Builder) {
+  Value *CondVal = SI.getCondition();
+  Value *TrueVal = SI.getTrueValue();
+  Value *FalseVal = SI.getFalseValue();
+
+  // Both arms must be selects with the same condition.
+  auto *Sel1 = dyn_cast<SelectInst>(TrueVal);
+  auto *Sel2 = dyn_cast<SelectInst>(FalseVal);
+  if (!Sel1 || !Sel2)
+    return nullptr;
+
+  Value *Cond1 = Sel1->getCondition();
+  Value *Cond2 = Sel2->getCondition();
+
+  // Get the "effective" true/false values accounting for NOT conditions
+  Value *T1 = Sel1->getTrueValue();
+  Value *F1 = Sel1->getFalseValue();
+  Value *T2 = Sel2->getTrueValue();
+  Value *F2 = Sel2->getFalseValue();
+
+  // Check if conditions are the same or inverted.
+  if (Cond1 != Cond2) {
+    // Check if conditions are inverted (NOT).
+    Value *NotCond1;
+    Value *NotCond2;
+    bool Cond1IsNot = match(Cond1, m_Not(m_Value(NotCond1)));
+    bool Cond2IsNot = match(Cond2, m_Not(m_Value(NotCond2)));
+
+    if (Cond1IsNot && Cond2IsNot && NotCond1 == NotCond2) {
+      // Both conditions are NOT of the same value.
+      Cond1 = NotCond1;
+      Cond2 = NotCond2;
+      // sel1 = !c1 ? T1 : F1 = c1 ? F1 : T1
+      // sel2 = !c1 ? T2 : F2 = c1 ? F2 : T2
+      std::swap(T1, F1);
+      std::swap(T2, F2);
+    } else if (Cond1IsNot && NotCond1 == Cond2) {
+      // Cond1 = NOT(Cond2)
+      Cond1 = NotCond1;
+      // sel1 = !c2 ? T1 : F1 = c2 ? F1 : T1
+      std::swap(T1, F1);
+    } else if (Cond2IsNot && NotCond2 == Cond1) {
+      // Cond2 = NOT(Cond1)
+      Cond2 = NotCond2;
+      // sel2 = !c1 ? T2 : F2 = c1 ? F2 : T2
+      std::swap(T2, F2);
+    } else {
+      return nullptr;
+    }
+  }
+
+  // Now Cond1 == Cond2. Check if the select arms are swapped.
+  // sel1 = c1 ? T1 : F1
+  // sel2 = c1 ? T2 : F2
+  // We need T1 == F2 and F1 == T2
+  if (T1 != F2 || F1 != T2)
+    return nullptr;
+
+  // Type check: ensure condition types match for XOR operation
+  if (Cond1->getType() != CondVal->getType())
+    return nullptr;
+
+  // Profitability check: avoid increasing instruction count.
+  // We're replacing 3 selects with 1 xor + 1 select.
+  // The inner selects must only be used by the outer select.
+  if (!Sel1->hasOneUse() || !Sel2->hasOneUse())
+    return nullptr;
+
+  // The pattern matches. Create: select (xor Cond1 CondVal), F1, T1
+  // Note: result = c2 ? (c1 ? T1 : F1) : (c1 ? F1 : T1)
+  // When c1 == c2: result = T1
+  // When c1 != c2: result = F1
+  // So result = (c1 xor c2) ? F1 : T1
+  Value *XorCond = Builder.CreateXor(Cond1, CondVal);
+  return SelectInst::Create(XorCond, F1, T1);
+}
 Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
   Value *CondVal = SI.getCondition();
   Value *TrueVal = SI.getTrueValue();
@@ -3990,6 +4077,9 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
   if (Instruction *I = foldNestedSelects(SI, Builder))
     return I;

+  if (Instruction *I = foldSelectOfSymmetricSelects(SI, Builder))
+    return I;
+
   // Match logical variants of the pattern,
   // and transform them iff that gets rid of inversions.
   //   (~x) | y  -->  ~(x & (~y))

log.source_program:
define i32 @select_of_symmetric_selects(i32 %a, i32 %b, i1 %c1, i1 %c2) {
  %sel1 = select i1 %c1, i32 %a, i32 %b
  %sel2 = select i1 %c1, i32 %b, i32 %a
  %ret = select i1 %c2, i32 %sel1, i32 %sel2
  ret i32 %ret
}

log.expect_optimized_program:
define i32 @select_of_symmetric_selects(i32 %a, i32 %b, i1 %c1, i1 %c2) {
  %1 = xor i1 %c1, %c2
  %ret = select i1 %1, i32 %b, i32 %a
  ret i32 %ret
}

